interface EQ {
  stem: string;
  options: string[];
  correctAnswer: number;
  rationale: string;
  learningObjective: string;
  blueprintCategory: string;
  subtopic: string;
  difficulty: number;
  cognitiveLevel: string;
  questionType: "multiple-choice" | "image-interpretation" | "calculation" | "clinical-case";
  scenario?: string;
  exhibitData?: any;
  exam: string;
  regionScope: "US" | "CAN" | "BOTH";
}

export function getBatch21(): EQ[] {
  return [
    { stem: "The mitral valve E-point septal separation (EPSS) is a rapid M-mode estimate of LV function. An EPSS >10 mm suggests:", options: ["Normal EF", "Reduced EF (typically <40%)", "Diastolic dysfunction only", "Mitral stenosis"], correctAnswer: 1, rationale: "EPSS measures the distance between the anterior mitral leaflet E-point and the ventricular septum on M-mode. EPSS >10 mm correlates with reduced EF (<40%). It increases with LV dilation and decreased MV opening (low stroke volume).", learningObjective: "Interpret EPSS for LV function estimation", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The myocardial performance index (Tei index) for the LV is calculated as:", options: ["ET / (IVCT + IVRT)", "(IVCT + IVRT) / ET", "IVCT / ET", "IVRT / ET"], correctAnswer: 1, rationale: "Tei index = (IVCT + IVRT) / ET. It combines systolic and diastolic function into a single index. Normal LV Tei index by PW Doppler is <0.40 (by TDI: <0.48). Values above these thresholds indicate global (systolic + diastolic) myocardial dysfunction.", learningObjective: "Calculate the Tei index", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In a normal heart, the mitral valve closes before the tricuspid valve because:", options: ["The LV contracts before the RV", "LV pressure rises faster than RV pressure due to greater muscle mass", "The mitral valve is smaller", "Both valves close simultaneously always"], correctAnswer: 1, rationale: "The mitral valve closes slightly before the tricuspid valve (M1 before T1) because LV pressure rises faster than RV pressure due to greater LV myocardial mass. This results in the normal splitting of S1 (though usually not audible). The reverse occurs with LBBB.", learningObjective: "Explain the timing of AV valve closure", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Physiology", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The interventricular septum receives its blood supply primarily from the:", options: ["Right coronary artery only", "LAD (anterior 2/3) and PDA (posterior 1/3)", "Left circumflex only", "Diagonal branches only"], correctAnswer: 1, rationale: "The interventricular septum receives dual blood supply: the anterior 2/3 from septal perforator branches of the LAD, and the posterior 1/3 from the PDA (from RCA in 85% or LCx in 15%). This dual supply makes complete septal infarction uncommon.", learningObjective: "Describe IVS blood supply", blueprintCategory: "Anatomy/Physiology", subtopic: "Coronary Artery Anatomy", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The RCA is dominant (supplies the PDA) in approximately what percentage of patients?", options: ["15%", "50%", "75%", "85%"], correctAnswer: 3, rationale: "Right dominance (RCA gives rise to PDA) occurs in ~85% of patients. Left dominance (LCx gives rise to PDA) occurs in ~8%. Co-dominant (both contribute) occurs in ~7%. Dominance determines which coronary supplies the inferior wall and posterior septum.", learningObjective: "State coronary dominance prevalence", blueprintCategory: "Anatomy/Physiology", subtopic: "Coronary Artery Anatomy", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal aortic valve opens in systole to an orifice of approximately:", options: ["1.0-1.5 cm²", "2.0-2.5 cm²", "3.0-4.0 cm²", "5.0-6.0 cm²"], correctAnswer: 2, rationale: "Normal aortic valve orifice area is 3.0-4.0 cm². The three cusps open widely during systole, creating a near-circular orifice. With aging and calcification, the orifice progressively narrows. Severe AS is defined as AVA <1.0 cm².", learningObjective: "State normal aortic valve orifice area", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal mitral valve orifice area is approximately:", options: ["1.0-2.0 cm²", "2.0-3.0 cm²", "4.0-6.0 cm²", "8.0-10.0 cm²"], correctAnswer: 2, rationale: "Normal mitral valve area is 4.0-6.0 cm². Mild MS: MVA 1.5-2.5 cm², moderate: 1.0-1.5 cm², severe: <1.0 cm². The mitral valve is the largest cardiac valve by orifice area.", learningObjective: "State normal mitral valve area", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An enlarged right atrium is defined as RA area exceeding:", options: ["10 cm²", "14 cm²", "18 cm²", "25 cm²"], correctAnswer: 2, rationale: "Normal RA area ≤18 cm² (end-systole, A4C view). RA area >18 cm² indicates RA enlargement. RA volume index >33 mL/m² is also abnormal. RA enlargement is seen in TR, pulmonary hypertension, ASD, and RV failure.", learningObjective: "State criteria for RA enlargement", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal RV wall thickness measured in subcostal view is:", options: ["<3 mm", "≤5 mm", "8-10 mm", ">12 mm"], correctAnswer: 1, rationale: "Normal RV free wall thickness ≤5 mm measured in the subcostal view at end-diastole. RV wall thickness >5 mm indicates RV hypertrophy, which is most commonly caused by pulmonary hypertension. The subcostal view provides the best acoustic window for this measurement.", learningObjective: "State normal RV wall thickness", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A dilated aortic root (sinuses of Valsalva) measuring 4.5 cm in a patient with Marfan syndrome warrants:", options: ["No follow-up", "Serial monitoring with consideration of prophylactic surgery if it reaches 5.0 cm", "Immediate surgery", "Beta-blocker therapy only"], correctAnswer: 1, rationale: "In Marfan syndrome, prophylactic aortic root replacement is recommended at ≥5.0 cm (or 4.5 cm with risk factors: family history of dissection, rapid growth >3 mm/year, or significant AR). At 4.5 cm, close serial monitoring (every 6-12 months) with beta-blocker/ARB therapy is indicated.", learningObjective: "Describe aortic root monitoring in Marfan syndrome", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 3, cognitiveLevel: "application", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Stanford classification of aortic dissection: Type B involves:", options: ["The ascending aorta", "Only the descending aorta (distal to the left subclavian artery)", "Both ascending and descending", "The aortic valve only"], correctAnswer: 1, rationale: "Stanford Type B: dissection involves only the descending aorta distal to the left subclavian artery origin. It is generally managed medically unless complicated (malperfusion, rupture, rapid expansion, refractory pain/hypertension). TEVAR is the preferred intervention for complicated Type B.", learningObjective: "Define Stanford Type B aortic dissection", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows an intimal flap in the ascending aorta with flow in both true and false lumens. The true lumen is identified by:", options: ["It is always larger", "Systolic expansion and often contains the higher velocity flow; the intimal flap bows toward the false lumen during systole", "It has spontaneous echo contrast", "It is always on the left side"], correctAnswer: 1, rationale: "The true lumen typically expands during systole (while the false lumen compresses) and the intimal flap bows toward the false lumen. The true lumen generally has higher velocity organized flow. The false lumen may contain spontaneous contrast or thrombus.", learningObjective: "Identify the true lumen in aortic dissection", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 4, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A penetrating atherosclerotic ulcer (PAU) of the aorta appears on echo as:", options: ["Normal aortic wall", "A crater-like ulceration penetrating through the intimal plaque into the media, typically in the descending aorta with atherosclerosis", "An intimal flap", "A dissection with dual lumens"], correctAnswer: 1, rationale: "PAU: ulceration of an atherosclerotic plaque that penetrates through the intima into the media. It typically occurs in the descending aorta of elderly patients with extensive atherosclerosis. It can lead to IMH, pseudoaneurysm, or frank dissection. TEE and CT are complementary for diagnosis.", learningObjective: "Describe PAU appearance on echo", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Aortic atheroma ≥4 mm thick or with mobile components is a risk factor for:", options: ["Valvular heart disease", "Systemic thromboembolism and stroke", "Pericarditis", "Endocarditis"], correctAnswer: 1, rationale: "Complex aortic atheroma (≥4 mm thick, mobile, ulcerated) in the aortic arch and descending aorta is an independent risk factor for stroke and peripheral embolism. It is best detected by TEE. Management includes anticoagulation and cardiovascular risk factor modification.", learningObjective: "Identify aortic atheroma as embolic risk factor", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient with Turner syndrome should have echo screening for:", options: ["Mitral prolapse only", "Bicuspid aortic valve, coarctation, and aortic dilation", "Tetralogy of Fallot", "Ebstein anomaly"], correctAnswer: 1, rationale: "Turner syndrome (45,X) is associated with bicuspid aortic valve (~30%), coarctation of the aorta (~10%), and aortopathy with risk of aortic dilation and dissection. Echo screening is recommended at diagnosis and serial follow-up for aortic root dimensions.", learningObjective: "Describe cardiac screening in Turner syndrome", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Down syndrome is most commonly associated with which congenital heart defect?", options: ["Tetralogy of Fallot", "Complete atrioventricular canal defect (AVSD)", "Transposition of great arteries", "Truncus arteriosus"], correctAnswer: 1, rationale: "Complete AVSD is the most common CHD in Down syndrome (trisomy 21), occurring in 40-50% of those with CHD. Other associations include VSD, ASD, PDA, and Tetralogy of Fallot. ~50% of Down syndrome patients have CHD.", learningObjective: "Identify the CHD most associated with Down syndrome", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A doubly committed subarterial VSD (supracristal VSD) is located:", options: ["In the muscular septum", "Below both the aortic and pulmonary valves in the conal (outlet) septum", "In the membranous septum", "At the AV canal level"], correctAnswer: 1, rationale: "Doubly committed subarterial (supracristal/outlet) VSD is located in the conal septum beneath both semilunar valves. It is more common in Asian populations. It is associated with prolapse of the right coronary cusp of the aortic valve into the VSD, causing progressive AR.", learningObjective: "Describe supracristal VSD location", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A muscular VSD differs from a perimembranous VSD in that muscular VSDs:", options: ["Are always large", "Are completely surrounded by muscle (no fibrous tissue), may be multiple ('Swiss cheese septum'), and have a higher rate of spontaneous closure", "Are always associated with AR", "Only occur in adults"], correctAnswer: 1, rationale: "Muscular VSDs are surrounded entirely by muscular tissue (unlike perimembranous which border fibrous tissue). They account for ~5-20% of VSDs, can be multiple, and have the highest rate of spontaneous closure (~80% in small defects). They may be difficult to visualize due to trabeculations.", learningObjective: "Differentiate muscular from perimembranous VSD", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo in a patient with Noonan syndrome may show:", options: ["Normal echo always", "Pulmonary valve stenosis (dysplastic valve), hypertrophic cardiomyopathy, and ASD", "Only aortic stenosis", "Only mitral prolapse"], correctAnswer: 1, rationale: "Noonan syndrome cardiac associations: pulmonary valve stenosis (~50%, often dysplastic valve that is less responsive to balloon valvuloplasty), HCM (~20-30%), ASD, and rarely coarctation. The phenotype overlaps with Turner syndrome but can affect both sexes.", learningObjective: "Describe cardiac findings in Noonan syndrome", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a patient with dextrocardia. The heart apex points to the:", options: ["Left", "Right", "Anteriorly", "Posteriorly"], correctAnswer: 1, rationale: "Dextrocardia: the cardiac apex points to the right. It can occur with situs inversus (mirror-image organ arrangement) or situs solitus (normal organ arrangement with isolated dextrocardia, which has higher association with congenital heart defects). Proper transducer positioning is essential for imaging.", learningObjective: "Define dextrocardia", blueprintCategory: "Anatomy/Physiology", subtopic: "Congenital Heart Defects", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The sinus venosus ASD is best detected by:", options: ["TTE parasternal views", "TEE (due to its location near the SVC-RA junction, which is poorly visualized on TTE)", "Subcostal views only", "M-mode"], correctAnswer: 1, rationale: "Sinus venosus ASD is located near the SVC-RA junction (superior type) or IVC-RA junction (inferior type, rare). It is often missed on TTE because the far-field IAS near the SVC is poorly resolved. TEE, cardiac MRI, or CT are more sensitive for detection.", learningObjective: "Identify the best modality for sinus venosus ASD detection", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Persistent left superior vena cava (PLSVC) is suspected on echo when:", options: ["The RA is enlarged", "The coronary sinus is dilated (>10 mm) and drains into the RA; confirmed by agitated saline injection in the left arm showing bubbles in the CS before the RA", "The IVC is dilated", "The aortic arch is right-sided"], correctAnswer: 1, rationale: "PLSVC drains into the dilated coronary sinus, which then empties into the RA. Diagnosis is confirmed by injecting agitated saline in the left arm: bubbles appear in the coronary sinus before the RA. PLSVC is the most common cause of a dilated coronary sinus (~0.3% of the general population).", learningObjective: "Diagnose persistent left SVC on echo", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Echo findings suggesting right heart pressure overload include all EXCEPT:", options: ["RV hypertrophy", "Systolic septal flattening", "IVC dilation with reduced collapse", "LV posterior wall thickening"], correctAnswer: 3, rationale: "RV pressure overload signs: RV hypertrophy (wall >5 mm), systolic septal flattening (D-sign), IVC dilation with reduced collapse, RA enlargement, TR with elevated RVSP, and notching of the RVOT Doppler profile. LV posterior wall thickening is not a sign of RV pressure overload.", learningObjective: "Identify signs of RV pressure overload", blueprintCategory: "Pathology Recognition", subtopic: "Hemodynamics", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In a CSCT context, the sonographer's role during a TEE procedure includes:", options: ["Performing the intubation", "Operating the echo machine, optimizing image acquisition, performing measurements, and assisting the physician during the procedure", "Prescribing sedation", "Interpreting the study independently"], correctAnswer: 1, rationale: "During TEE, the cardiac sonographer operates the echo machine, optimizes images, records clips, performs real-time measurements, and assists the physician (cardiologist/anesthesiologist) who manipulates the probe. The sonographer must be familiar with TEE views and probe controls.", learningObjective: "Describe the sonographer's role during TEE", blueprintCategory: "Ultrasound Physics", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "In the CSCT exam, knowledge of normal anatomic variants is important because they can mimic:", options: ["Nothing clinically significant", "Pathologic masses, thrombi, or vegetations (e.g., Eustachian valve, Chiari network, crista terminalis, Lambl excrescences)", "Only valvular stenosis", "Only arrhythmias"], correctAnswer: 1, rationale: "Normal anatomic variants that mimic pathology: Eustachian valve (RA mass), Chiari network (RA thrombus/vegetation), crista terminalis (RA tumor), Lambl excrescences (valve vegetation), moderator band (RV thrombus), false tendons (LV mass). Recognition prevents misdiagnosis.", learningObjective: "List normal variants that mimic pathology", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The left ventricle has how many papillary muscles?", options: ["One", "Two (anterolateral and posteromedial)", "Three", "Four"], correctAnswer: 1, rationale: "The LV has two papillary muscles: anterolateral (supplied by LAD and LCx - dual supply) and posteromedial (supplied by a single coronary, usually PDA from RCA). The posteromedial papillary muscle's single blood supply makes it more vulnerable to ischemic rupture.", learningObjective: "Describe LV papillary muscle anatomy and blood supply", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The posteromedial papillary muscle is more susceptible to ischemic rupture than the anterolateral because:", options: ["It is larger", "It has a single coronary artery blood supply (usually from the PDA/RCA) unlike the anterolateral which has dual supply", "It has more chordae", "It is closer to the apex"], correctAnswer: 1, rationale: "The posteromedial papillary muscle typically receives blood from a single coronary artery (PDA, usually from RCA), making it vulnerable to ischemia in inferior MI. The anterolateral papillary muscle has dual supply (LAD + LCx), providing collateral protection.", learningObjective: "Explain why posteromedial papillary muscle is vulnerable to ischemia", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The mitral valve anterior leaflet is in fibrous continuity with the:", options: ["Tricuspid valve", "Aortic valve (mitroaortic curtain/intervalvular fibrosa)", "Pulmonic valve", "Coronary sinus"], correctAnswer: 1, rationale: "The anterior mitral leaflet is in direct fibrous continuity with the aortic valve through the aorto-mitral curtain (intervalvular fibrosa). This relationship is important in endocarditis (infection can spread between these valves) and in understanding subaortic obstruction in HCM.", learningObjective: "Describe the mitroaortic fibrous continuity", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The superior vena cava can be visualized on TTE from the:", options: ["Apical view only", "Right parasternal and suprasternal views, and sometimes the subcostal view", "PLAX only", "Cannot be seen on TTE"], correctAnswer: 1, rationale: "The SVC can be visualized on TTE from the right parasternal view, suprasternal notch view, and sometimes the modified subcostal view. These windows are useful for detecting SVC dilation, sinus venosus ASD, and anomalous pulmonary venous connection.", learningObjective: "Identify TTE views for SVC visualization", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Views", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The strain pattern in Takotsubo cardiomyopathy typically shows:", options: ["Normal GLS", "Reduced apical strain with preserved basal strain (opposite of the amyloid pattern)", "Apical sparing pattern", "Only septal abnormalities"], correctAnswer: 1, rationale: "Takotsubo: reduced apical and mid-ventricular strain with relatively preserved basal strain. This is the opposite of the cardiac amyloidosis pattern (apical sparing). GLS is reduced acutely but typically recovers as the cardiomyopathy resolves over weeks.", learningObjective: "Describe strain pattern in Takotsubo", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 4, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Chemotherapy-related cardiac dysfunction (CTRCD) is defined as a decline in LVEF of:", options: [">5% to below normal range", ">10% from baseline to a value below 53%", ">20% from baseline", "Any decline"], correctAnswer: 1, rationale: "CTRCD: LVEF decline >10 percentage points from baseline to a value below 53% (lower limit of normal). GLS decline >15% relative from baseline is more sensitive for early detection. Serial monitoring during chemotherapy allows early intervention with cardioprotective agents.", learningObjective: "Define CTRCD diagnostic criteria", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "GLS is more sensitive than LVEF for detecting early cardiotoxicity from chemotherapy because:", options: ["GLS is easier to measure", "GLS detects subclinical myocardial dysfunction before EF declines, as longitudinal function is affected first", "GLS is more reproducible across vendors", "EF cannot be measured during chemotherapy"], correctAnswer: 1, rationale: "Longitudinal myocardial fibers (subendocardial) are affected earliest by cardiotoxic agents. GLS detects this subclinical dysfunction before global EF declines, allowing early cardioprotective therapy (beta-blockers, ACE inhibitors). A relative GLS decline >15% from baseline is prognostically significant.", learningObjective: "Explain why GLS is more sensitive than EF for cardiotoxicity", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the evaluation of native valve endocarditis, TTE has a sensitivity of approximately:", options: ["30-40%", "50-60%", "60-75%", "95-100%"], correctAnswer: 2, rationale: "TTE sensitivity for native valve endocarditis is approximately 60-75%. TEE sensitivity is >90-95%. TTE is the first-line test; TEE is indicated when TTE is negative but clinical suspicion remains high, for prosthetic valves, or to assess complications (abscess, fistula).", learningObjective: "State TTE sensitivity for native valve endocarditis", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A right-sided aortic arch is associated with which congenital heart defect?", options: ["ASD", "Tetralogy of Fallot (~25% of cases)", "Mitral prolapse", "Coarctation"], correctAnswer: 1, rationale: "Right aortic arch occurs in ~25% of Tetralogy of Fallot cases and is also associated with truncus arteriosus and other conotruncal defects. It is identified on the suprasternal view when the arch curves to the right instead of the left.", learningObjective: "Associate right aortic arch with congenital heart defects", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The 'Mercedes-Benz sign' on the PSAX view of the aortic valve represents:", options: ["A bicuspid valve", "Normal trileaflet aortic valve with three cusps forming a Y-shape in diastole", "Quadricuspid valve", "Severe calcification"], correctAnswer: 1, rationale: "The Mercedes-Benz sign (inverted Y or peace sign) represents the three commissures of a normal trileaflet aortic valve seen in diastole on the PSAX view. The three cusps coapt in the center. Absence of this pattern suggests bicuspid (two commissures) or unicuspid valve.", learningObjective: "Identify the Mercedes-Benz sign of normal aortic valve", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 1, cognitiveLevel: "recall", questionType: "image-interpretation", exam: "RDCS-AE", regionScope: "BOTH", exhibitData: { description: "PSAX view showing normal trileaflet aortic valve in diastole with three-pointed star configuration", findings: ["Three cusps", "Central coaptation point", "Y-shaped commissures"] } },
    { stem: "Subclinical rheumatic heart disease detected by echo screening in endemic regions shows:", options: ["Only mitral stenosis", "Morphologic valve changes (thickened leaflet tips, restricted posterior mitral leaflet motion) with or without mild pathologic regurgitation", "Only aortic stenosis", "Pericardial constriction"], correctAnswer: 1, rationale: "Subclinical RHD: morphologic changes detectable by echo before clinical presentation. World Heart Federation criteria include: pathologic MR (jet length ≥2 cm, velocity ≥3 m/s, pansystolic, seen in ≥2 views) combined with morphologic features (thickened leaflets >3 mm, restricted posterior leaflet, excessive tip motion).", learningObjective: "Describe subclinical RHD echo criteria", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the CSCT exam, understanding of the scope of practice for cardiac sonographers in Canada includes:", options: ["Independent interpretation of studies", "Performing the technical examination, optimizing image quality, performing measurements, preliminary assessment of findings, and recognizing critical findings for immediate reporting", "Prescribing treatment", "Independent reporting"], correctAnswer: 1, rationale: "Canadian cardiac sonographers perform the technical examination, optimize images, make measurements, provide preliminary technical observations, and recognize critical findings. Final interpretation and reporting is the responsibility of the physician (cardiologist). Scope of practice is defined by provincial regulatory bodies.", learningObjective: "Describe Canadian cardiac sonographer scope of practice", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "CSCT candidates should understand that the minimum training requirement for cardiac sonography in Canada typically includes:", options: ["No formal training", "Completion of an accredited cardiac sonography program (typically 2+ years) with clinical training hours", "Only online courses", "Only 6 months of training"], correctAnswer: 1, rationale: "Canadian cardiac sonography training typically requires completion of an accredited program (2-3 years) including didactic education and supervised clinical training hours. CSCT certification requires passing the examination and maintaining continuing education credits.", learningObjective: "State Canadian cardiac sonography training requirements", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
  ];
}

export function getBatch22(): EQ[] {
  return [
    { stem: "A peak aortic valve velocity of 3.5 m/s and a mean gradient of 25 mmHg indicate:", options: ["Mild AS", "Moderate AS", "Severe AS", "Normal valve"], correctAnswer: 1, rationale: "Moderate AS criteria: peak velocity 3.0-4.0 m/s, mean gradient 20-40 mmHg, AVA 1.0-1.5 cm². This patient's peak velocity of 3.5 m/s and mean gradient of 25 mmHg fall within the moderate range.", learningObjective: "Classify moderate aortic stenosis", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 2, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Severe aortic regurgitation vena contracta width is:", options: ["<3 mm", "3-5 mm", "≥6 mm", "<1 mm"], correctAnswer: 2, rationale: "Severe AR: vena contracta ≥6 mm (measured in the PLAX view, perpendicular to the jet at its narrowest point). Other severe AR criteria: PHT <200 ms, holodiastolic flow reversal in descending aorta, regurgitant volume ≥60 mL, EROA ≥0.30 cm².", learningObjective: "State vena contracta criteria for severe AR", blueprintCategory: "Hemodynamic Measurements", subtopic: "Valvular Disease Assessment", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The AR pressure half-time of <200 ms indicates:", options: ["Mild AR", "Moderate AR", "Severe AR (rapid equalization of aortic and LV pressures)", "Normal"], correctAnswer: 2, rationale: "AR PHT <200 ms: severe AR. PHT 200-500 ms: moderate AR. PHT >500 ms: mild AR. A short PHT indicates rapid equalization of aortic and LV pressures due to massive regurgitation. However, chronic severe AR with elevated LVEDP may also have short PHT.", learningObjective: "Interpret AR pressure half-time", blueprintCategory: "Hemodynamic Measurements", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The AR jet width to LVOT width ratio that indicates severe AR is:", options: ["<25%", "25-45%", "46-64%", "≥65%"], correctAnswer: 3, rationale: "AR jet width/LVOT width ratio: mild <25%, moderate 25-64%, severe ≥65%. Measured in the PLAX view immediately below the aortic valve. This is a semi-quantitative color Doppler parameter complementing other severity indices.", learningObjective: "State AR jet width/LVOT ratio for severe AR", blueprintCategory: "Hemodynamic Measurements", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Functional (secondary) mitral regurgitation is caused by:", options: ["Intrinsic leaflet disease", "LV remodeling causing annular dilation and leaflet tethering with structurally normal leaflets", "Rheumatic disease", "Myxomatous degeneration"], correctAnswer: 1, rationale: "Functional MR: structurally normal leaflets that fail to coapt due to LV remodeling (ischemic or dilated cardiomyopathy). Mechanisms include annular dilation, papillary muscle displacement, and leaflet tethering. Treatment focuses on the underlying LV disease, not the valve itself.", learningObjective: "Describe the mechanism of functional MR", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The tenting height (coaptation depth) of the mitral valve in functional MR is measured as:", options: ["The distance from the annular plane to the coaptation point of the leaflets; tenting height >10 mm indicates significant tethering", "The leaflet length", "The annular diameter only", "The jet area"], correctAnswer: 0, rationale: "Tenting height: the perpendicular distance from the mitral annular plane to the point of leaflet coaptation. Increased tenting (>10 mm) indicates significant leaflet tethering and predicts poor response to annuloplasty alone. Tenting area (the enclosed area beneath the leaflets) is also measured.", learningObjective: "Define mitral valve tenting height", blueprintCategory: "Hemodynamic Measurements", subtopic: "Valvular Disease Assessment", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In mitral stenosis, planimetry of the mitral valve area is performed in which view?", options: ["Apical four-chamber view", "Parasternal short-axis view at the mitral valve level", "Suprasternal view", "Subcostal view"], correctAnswer: 1, rationale: "MVA planimetry is performed in the PSAX view at the tips of the mitral leaflets in early diastole (maximal opening). The inner contour of the valve orifice is traced. It is considered the reference standard for MVA measurement and is independent of hemodynamic conditions.", learningObjective: "Describe MVA planimetry technique", blueprintCategory: "Hemodynamic Measurements", subtopic: "Valvular Disease Assessment", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A mitral valve gradient increases with:", options: ["Decreased heart rate", "Increased heart rate (shortened diastolic filling time) and increased cardiac output", "Decreased cardiac output", "Lower LA pressure"], correctAnswer: 1, rationale: "MS gradients are flow-dependent: they increase with tachycardia (shortened diastole = less filling time), exercise, anemia, pregnancy, and high-output states. Gradients decrease with bradycardia. This is why MVA (planimetry or PHT) is preferred over gradients alone for severity assessment.", learningObjective: "Explain factors affecting MS gradient", blueprintCategory: "Hemodynamic Measurements", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Degenerative mitral annular calcification (MAC) is commonly seen in:", options: ["Young athletes", "Elderly patients, particularly women, with hypertension, diabetes, and chronic kidney disease", "Only patients with rheumatic disease", "Only in Marfan syndrome"], correctAnswer: 1, rationale: "MAC: degenerative calcification of the mitral annulus, common in elderly patients (especially women) with risk factors including hypertension, diabetes, CKD, and hyperparathyroidism. Severe MAC can restrict leaflet motion, cause MS or MR, and increase stroke risk.", learningObjective: "Identify risk factors for MAC", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Coanda effect in echocardiography refers to:", options: ["Normal blood flow pattern", "A regurgitant jet that adheres to and travels along a cardiac wall, causing underestimation of severity by jet area method", "An artifact from calcification", "Doppler aliasing"], correctAnswer: 1, rationale: "The Coanda effect: a fluid jet adjacent to a surface tends to adhere to that surface. In echo, eccentric MR or AR jets hug the chamber wall and appear smaller on color Doppler than their true severity. This leads to underestimation of regurgitation severity by jet area.", learningObjective: "Describe the Coanda effect in echo", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In color Doppler, the color map convention is:", options: ["Red and blue have no specific meaning", "Red = flow toward the transducer, blue = flow away from the transducer", "Red = arterial, blue = venous", "Red = high velocity, blue = low velocity"], correctAnswer: 1, rationale: "Standard color Doppler convention: red = flow toward the transducer (positive Doppler shift), blue = flow away (negative Doppler shift). Aliasing appears as color reversal (red to blue or vice versa). Variance mode adds green to the color map to indicate turbulent flow.", learningObjective: "Describe color Doppler convention", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The color Doppler gain should be set to:", options: ["Maximum to see all flow", "Just below the level that produces random color noise in tissue (so that no color appears outside of blood flow areas)", "Minimum setting", "A fixed standard value"], correctAnswer: 1, rationale: "Color Doppler gain is optimized by increasing until random color pixels appear in non-flow areas (tissue/myocardium), then reducing slightly until they disappear. This maximizes sensitivity for detecting flow while minimizing artifact. Too high = color bleeding; too low = missed flow.", learningObjective: "Describe proper color Doppler gain setting", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 2, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The spectral broadening seen on PW Doppler indicates:", options: ["Laminar flow", "Turbulent flow with a wide range of velocities present in the sample volume", "No flow", "Aliasing"], correctAnswer: 1, rationale: "Spectral broadening: filling in of the spectral window (normally clear below the velocity envelope in laminar flow). It indicates disturbed/turbulent flow with a wide range of velocities within the sample volume. It is seen in stenotic and regurgitant jets.", learningObjective: "Interpret spectral broadening on PW Doppler", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A sample volume placed too large on PW Doppler may result in:", options: ["Better spectral display", "Spectral broadening due to inclusion of different velocity profiles within the large sample volume", "Higher Nyquist limit", "Better range resolution"], correctAnswer: 1, rationale: "A large sample volume includes velocities from a wider area, leading to spectral broadening. For accurate measurements, the sample volume should be as small as practical (typically 1-3 mm) and placed precisely at the point of interest (valve tips, LVOT).", learningObjective: "Explain effect of sample volume size on PW Doppler", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Doppler wall filter:", options: ["Enhances wall motion", "Removes low-frequency, high-amplitude signals from cardiac wall and valve motion to display only blood flow signals", "Increases sensitivity to blood flow", "Removes all Doppler signal"], correctAnswer: 1, rationale: "The wall filter (high-pass filter) removes low-frequency Doppler signals from slowly moving structures (cardiac walls, valves). Setting it too high can remove low-velocity blood flow signals (e.g., diastolic filling). For TDI, the wall filter is set low to detect myocardial motion.", learningObjective: "Describe the Doppler wall filter function", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Dynamic LVOT obstruction in HCM can be provoked by:", options: ["Increasing preload", "Valsalva maneuver (decreases preload), standing, post-PVC beats, amyl nitrite, exercise, dehydration", "Squatting", "Leg elevation"], correctAnswer: 1, rationale: "Dynamic LVOT obstruction increases with: decreased preload (Valsalva, standing, dehydration), decreased afterload (amyl nitrite), increased contractility (post-PVC, exercise, dobutamine). It decreases with increased preload (squatting, leg elevation, IV fluids) and increased afterload (phenylephrine, handgrip).", learningObjective: "List provocative maneuvers for LVOT obstruction in HCM", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Brockenbrough-Braunwald-Morrow sign in HCM refers to:", options: ["Decreased gradient after a PVC", "Increased LVOT gradient and decreased pulse pressure in the beat following a PVC", "Normal response to exercise", "Decreased gradient with Valsalva"], correctAnswer: 1, rationale: "After a PVC, the post-extrasystolic beat has increased contractility (post-extrasystolic potentiation), which in HCM causes increased SAM and LVOT obstruction. This paradoxically decreases pulse pressure (instead of increasing it as in fixed AS). This is the Brockenbrough sign.", learningObjective: "Describe the Brockenbrough-Braunwald-Morrow sign", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 5, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In HCM with LVOT obstruction, the MR jet is typically directed:", options: ["Anteriorly", "Posteriorly (away from the SAM of the anterior leaflet)", "Centrally", "Laterally"], correctAnswer: 1, rationale: "In obstructive HCM, SAM causes malcoaptation of the mitral leaflets, resulting in MR directed posteriorly (away from the anterior leaflet). The timing is mid-to-late systolic (corresponding to SAM onset). An anteriorly directed MR jet suggests intrinsic MR from a different mechanism.", learningObjective: "Describe MR jet direction in obstructive HCM", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Endomyocardial fibrosis is characterized by:", options: ["Ventricular dilation", "Dense fibrotic endocardial thickening of the ventricular apices with apical obliteration and restrictive physiology", "Hypertrophic septum", "Only pericardial effusion"], correctAnswer: 1, rationale: "Endomyocardial fibrosis: dense endocardial fibrosis and calcification, predominantly affecting the ventricular apices and subvalvular apparatus. The apices are obliterated by thrombus and fibrosis. Restrictive filling results from reduced ventricular compliance. It is common in tropical regions.", learningObjective: "Describe endomyocardial fibrosis echo findings", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Löffler endocarditis (hypereosinophilic syndrome) on echo shows:", options: ["Normal findings", "Thickened endocardium with apical thrombus and restrictive filling, associated with eosinophilia", "Only aortic stenosis", "Ventricular dilation"], correctAnswer: 1, rationale: "Löffler endocarditis: eosinophilic infiltration of the myocardium causes three phases: (1) acute necrotic (myocarditis), (2) thrombotic (endocardial thrombus, especially apical), (3) fibrotic (restrictive). Echo shows apical thrombus, endocardial thickening, and restrictive physiology.", learningObjective: "Describe Löffler endocarditis echo findings", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 5, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A Doppler-derived cardiac output of 3.5 L/min in a patient with BSA 1.8 m² gives a cardiac index of:", options: ["1.5 L/min/m²", "1.94 L/min/m²", "2.5 L/min/m²", "3.0 L/min/m²"], correctAnswer: 1, rationale: "CI = CO / BSA = 3.5 / 1.8 = 1.94 L/min/m². This is below normal (2.5-4.0) and indicates low cardiac output. In the ICU setting, this may indicate need for inotropic support or volume optimization.", learningObjective: "Calculate and interpret low cardiac index", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "application", questionType: "calculation", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient with an LVOT diameter of 1.8 cm, LVOT VTI of 15 cm, AV VTI of 80 cm. After low-dose dobutamine, LVOT VTI increases to 22 cm and AV VTI to 90 cm. The post-dobutamine AVA is:", options: ["0.48 cm²", "0.62 cm²", "0.75 cm²", "0.90 cm²"], correctAnswer: 1, rationale: "LVOT area = π(0.9)² = 2.54 cm². Post-dobutamine AVA = (2.54 × 22) / 90 = 55.88 / 90 = 0.62 cm². Since AVA remains <1.0 cm² with increased flow, this is true severe AS (not pseudo-severe). Pseudo-severe AS would show AVA increasing to >1.0 cm² with dobutamine.", learningObjective: "Interpret dobutamine stress echo in low-flow AS", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 5, cognitiveLevel: "analysis", questionType: "calculation", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "CSCT candidates must understand that echo measurements should be performed:", options: ["Only once", "According to ASE/EACVI guidelines with standardized techniques, measuring at specific cardiac cycle phases, and using recommended view for each parameter", "In any view available", "Only by the interpreting physician"], correctAnswer: 1, rationale: "Standardized measurement techniques per ASE/EACVI guidelines ensure accuracy and reproducibility. Each measurement has a specific recommended view, cardiac cycle phase (end-diastole/end-systole), and methodology (leading edge, inner edge, etc.). Adherence to standards is essential for reliable results.", learningObjective: "Describe standardized echo measurement requirements", blueprintCategory: "Hemodynamic Measurements", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "In the CSCT exam, knowledge of echo in pregnancy includes understanding that:", options: ["Echo is contraindicated", "Physiologic changes of pregnancy (increased CO, mild valve regurgitation, small pericardial effusion) are normal and must be distinguished from pathology", "Pregnancy has no effect on echo findings", "Only TEE should be used"], correctAnswer: 1, rationale: "Normal pregnancy echo changes: increased CO (40-50%), mild chamber dilation, physiologic TR/PR/MR, small pericardial effusion, and slightly increased LVOT velocity. CSCT candidates must distinguish these normal changes from pathologic conditions (peripartum cardiomyopathy, valvular disease).", learningObjective: "Describe normal pregnancy echo changes", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "An elevated E/A ratio (>2) with very short deceleration time (<150 ms) in a patient with heart failure indicates:", options: ["Normal diastolic function", "Grade I diastolic dysfunction", "Grade III (restrictive) diastolic dysfunction", "Inadequate study"], correctAnswer: 2, rationale: "E/A >2 with DT <150 ms represents a restrictive filling pattern (Grade III if irreversible with Valsalva, Grade IV/reversible if it reverts to impaired relaxation with Valsalva). This indicates markedly elevated filling pressures and advanced diastolic dysfunction with poor prognosis.", learningObjective: "Identify restrictive filling pattern", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Mitral annular calcification can cause which hemodynamic abnormality?", options: ["Only regurgitation", "Both mitral stenosis (by restricting leaflet motion) and mitral regurgitation (by preventing proper coaptation)", "Only stenosis", "No hemodynamic effect"], correctAnswer: 1, rationale: "Severe MAC can restrict leaflet excursion causing functional MS (calcified annulus limits opening), prevent proper leaflet coaptation causing MR, or both. MAC-related MS has different morphology from rheumatic MS and is generally not suitable for balloon valvotomy.", learningObjective: "Describe hemodynamic effects of MAC", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a mobile, pedunculated mass in the LA attached to the fossa ovalis with areas of hemorrhage. The most likely diagnosis is:", options: ["Thrombus", "LA myxoma", "Vegetation", "Lipoma"], correctAnswer: 1, rationale: "Classic LA myxoma: pedunculated, mobile mass attached to the fossa ovalis (IAS) by a stalk, often heterogeneous with areas of hemorrhage, necrosis, or calcification. It can prolapse through the MV causing obstruction (tumor plop). Surgical excision is curative with low recurrence.", learningObjective: "Diagnose LA myxoma on echo", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 2, cognitiveLevel: "application", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Metastatic cardiac tumors are how many times more common than primary cardiac tumors?", options: ["2-5 times", "5-10 times", "20-40 times", "100 times"], correctAnswer: 2, rationale: "Metastatic cardiac tumors are 20-40 times more common than primary cardiac tumors. Common primary cancers that metastasize to the heart include lung, breast, melanoma, lymphoma, and renal cell carcinoma. Pericardial involvement (effusion) is the most common manifestation.", learningObjective: "Compare frequency of metastatic vs primary cardiac tumors", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A rhabdomyoma is the most common primary cardiac tumor in:", options: ["Adults", "Children (associated with tuberous sclerosis)", "Elderly patients", "Athletes"], correctAnswer: 1, rationale: "Rhabdomyoma: most common cardiac tumor in children, with ~50-80% associated with tuberous sclerosis. They are typically multiple, arise from the ventricular myocardium, and often regress spontaneously. Surgery is reserved for hemodynamically significant or arrhythmogenic tumors.", learningObjective: "Identify the most common pediatric cardiac tumor", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "During a TEE-guided MitraClip procedure, the echo is used to:", options: ["Only guide vascular access", "Guide transseptal puncture, position the clip on the mitral leaflets, assess residual MR, and monitor for complications", "Only assess LV function", "Only measure gradient"], correctAnswer: 1, rationale: "TEE is essential for MitraClip: guides transseptal puncture (optimal location in the IAS), steers the clip to the correct position on the mitral leaflets, assesses leaflet grasping and residual MR, evaluates for MS (post-clip gradient), and monitors for complications (pericardial effusion, device embolization).", learningObjective: "Describe TEE role in MitraClip procedure", blueprintCategory: "Ultrasound Physics", subtopic: "Advanced Echo Techniques", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In Canadian echo practice, continuing professional development (CPD) requirements for CSCT-certified sonographers include:", options: ["No ongoing requirements", "Regular CPD credits in cardiac ultrasound topics to maintain certification", "Only attending one conference", "Only repeating the certification exam"], correctAnswer: 1, rationale: "CSCT-certified sonographers must maintain their certification through continuing professional development, including earning CPD credits through approved educational activities in cardiac ultrasound. This ensures knowledge currency and competence maintenance.", learningObjective: "Describe CSCT CPD requirements", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
  ];
}

export function getBatch23(): EQ[] {
  return [
    { stem: "A patient with hemolytic anemia after mechanical valve replacement has:", options: ["Normal valve function", "Possible paravalvular leak causing red blood cell destruction from shear forces", "Only mild fatigue", "Endocarditis"], correctAnswer: 1, rationale: "Hemolytic anemia after mechanical valve replacement suggests paravalvular leak (PVL) with RBC fragmentation from shear stress at the leak site. Schistocytes on blood smear and elevated LDH confirm hemolysis. TEE is needed for PVL assessment, as TTE has limited sensitivity.", learningObjective: "Associate hemolytic anemia with PVL", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "On TEE, the normal interatrial septum shows a thin region called the:", options: ["Crista terminalis", "Fossa ovalis (the remnant of the foramen ovale)", "Coronary sinus", "Eustachian valve"], correctAnswer: 1, rationale: "The fossa ovalis is the thin, central portion of the IAS that represents the closed foramen ovale. It is the most common site for ASD (secundum type), PFO, and the target for transseptal puncture. Lipomatous hypertrophy characteristically spares the fossa ovalis.", learningObjective: "Identify the fossa ovalis on TEE", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An LVOT diameter measurement error of 1 mm will cause approximately what percentage error in AVA calculation?", options: ["1-2%", "5-7%", "7-10%", "15-20%"], correctAnswer: 2, rationale: "LVOT diameter is squared to calculate area (πr²), so small errors are amplified. A 1 mm error in a 20 mm LVOT diameter changes the radius by 0.5 mm, resulting in approximately 7-10% error in area and consequently in AVA. This is the most important source of error in the continuity equation.", learningObjective: "Understand LVOT measurement error impact on AVA", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 4, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal pulmonic valve PW Doppler velocity is:", options: ["<0.3 m/s", "<1.0 m/s (typically 0.6-0.9 m/s)", "1.5-2.0 m/s", ">3.0 m/s"], correctAnswer: 1, rationale: "Normal pulmonic valve velocity is <1.0 m/s (typically 0.6-0.9 m/s). The PW Doppler sample volume is placed just distal to the valve leaflets in the PSAX or RV outflow view. Elevated velocity suggests pulmonary stenosis or increased pulmonary flow.", learningObjective: "State normal pulmonic valve velocity", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal aortic valve peak velocity on Doppler is:", options: ["<0.5 m/s", "<2.0 m/s (typically 1.0-1.7 m/s)", "2.5-3.0 m/s", ">4.0 m/s"], correctAnswer: 1, rationale: "Normal aortic valve peak velocity is <2.0 m/s (typically 1.0-1.7 m/s). Peak velocity 2.0-2.5 m/s suggests aortic sclerosis. Peak velocity 2.5-3.0 m/s is mild AS. >3.0 m/s is moderate, and >4.0 m/s is severe AS.", learningObjective: "State normal aortic valve peak velocity", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal mitral E wave velocity is:", options: ["0.1-0.3 m/s", "0.6-1.0 m/s", "1.5-2.0 m/s", ">2.5 m/s"], correctAnswer: 1, rationale: "Normal mitral E wave velocity is 0.6-1.0 m/s (varies with age). E velocity >1.5 m/s may indicate mitral stenosis or high-output state. The sample volume is placed at the mitral leaflet tips in the A4C view for inflow assessment.", learningObjective: "State normal mitral E wave velocity", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal LVOT VTI is approximately:", options: ["5-10 cm", "18-22 cm", "30-40 cm", "50-60 cm"], correctAnswer: 1, rationale: "Normal LVOT VTI is approximately 18-22 cm (range varies with stroke volume). LVOT VTI <18 cm may indicate reduced stroke volume. It is measured by PW Doppler with the sample volume placed 5-10 mm proximal to the aortic valve in the A5C view.", learningObjective: "State normal LVOT VTI", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In acute pulmonary embolism, echo may show all of the following EXCEPT:", options: ["RV dilation", "McConnell sign", "Elevated TR velocity/RVSP", "Concentric LV hypertrophy"], correctAnswer: 3, rationale: "Acute PE echo findings: RV dilation (RV:LV >1.0), McConnell sign, elevated RVSP (usually <60 mmHg in acute PE), IVC dilation, septal flattening, and TR. Concentric LV hypertrophy is not a finding of PE; it is associated with chronic hypertension.", learningObjective: "Identify echo findings NOT associated with acute PE", blueprintCategory: "Pathology Recognition", subtopic: "Hemodynamics", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In chronic thromboembolic pulmonary hypertension (CTEPH), the RVSP is typically:", options: ["<30 mmHg", "30-50 mmHg", ">60 mmHg (often markedly elevated due to chronic obstruction)", "Normal"], correctAnswer: 2, rationale: "CTEPH: chronic obstruction of pulmonary arteries causes sustained elevation of PA pressures. Unlike acute PE (RVSP usually <60 mmHg because the non-hypertrophied RV cannot generate higher pressures), CTEPH allows RV hypertrophy and adaptation, enabling RVSP >60-100+ mmHg.", learningObjective: "Differentiate RVSP in acute PE vs CTEPH", blueprintCategory: "Pathology Recognition", subtopic: "Hemodynamics", difficulty: 4, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Cardiac MRI is superior to echo for:", options: ["Real-time valve assessment", "Myocardial tissue characterization (fibrosis, edema, iron), RV quantification, and complex congenital anatomy", "Hemodynamic calculations", "Bedside assessment"], correctAnswer: 1, rationale: "CMR advantages over echo: myocardial tissue characterization (LGE for fibrosis, T2 for edema, T1/T2* mapping for amyloid/iron), accurate RV volumes and function, complex congenital anatomy, and arrhythmogenic substrates. Echo advantages: bedside availability, real-time hemodynamics, lower cost.", learningObjective: "Identify CMR advantages over echo", blueprintCategory: "Ultrasound Physics", subtopic: "Advanced Echo Techniques", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the CSCT exam, knowledge of the differences between Canadian and American echo certification pathways includes understanding that CSCT is:", options: ["Identical to ARDMS", "The Canadian certification specifically designed for cardiac sonographers working in Canada, with content relevant to Canadian practice standards", "Only for physicians", "Not recognized"], correctAnswer: 1, rationale: "CSCT is the Canadian certification body for cardiac sonographers, distinct from ARDMS (American). While core knowledge overlaps, CSCT includes Canadian-specific content (healthcare system, scope of practice, provincial regulations, Canadian guidelines). Both are respected credentials.", learningObjective: "Differentiate CSCT from ARDMS certification", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "An echo measurement of the aortic annulus for TAVR sizing should ideally use:", options: ["2D TTE only", "3D TEE for accurate elliptical annular measurements, as the annulus is oval (not circular)", "M-mode", "Only CT"], correctAnswer: 1, rationale: "The aortic annulus is oval/elliptical, not circular. 3D TEE provides accurate measurements of the major and minor axes and perimeter-derived diameter. 2D measurements (single diameter) can undersize or oversize the prosthesis. CT angiography is also used for preprocedural sizing.", learningObjective: "Describe optimal aortic annulus measurement for TAVR", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 4, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "CSCT examination includes knowledge of echo findings in adult congenital heart disease because:", options: ["It is not included", "The population of adults with CHD is growing, and cardiac sonographers must recognize repaired and unrepaired congenital lesions", "Only pediatric sonographers need this knowledge", "CHD is rare in adults"], correctAnswer: 1, rationale: "Due to advances in surgical repair, >90% of children with CHD survive to adulthood. Canadian cardiac sonographers increasingly encounter adults with repaired/palliated CHD. CSCT tests knowledge of common lesions, surgical repairs, and residual/sequelae findings.", learningObjective: "Explain why adult CHD knowledge is important for CSCT", blueprintCategory: "Pathology Recognition", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "After Fontan palliation for single ventricle physiology, the echo characteristically shows:", options: ["Normal biventricular anatomy", "A single functioning ventricle, absent pulmonary valve flow (passive pulmonary blood flow from Fontan pathway), and possible systemic venous congestion", "Isolated ASD", "Only mild MR"], correctAnswer: 1, rationale: "Post-Fontan echo: single functional ventricle (may be morphologic LV or RV), Fontan connection (systemic veins routed directly to PAs), absent subpulmonic ventricle/valve, and passive pulmonary blood flow. Long-term issues include ventricular dysfunction, AV valve regurgitation, and protein-losing enteropathy.", learningObjective: "Describe post-Fontan echo findings", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 5, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A tissue Doppler s' velocity at the mitral annulus <5 cm/s indicates:", options: ["Normal systolic function", "Severely impaired LV longitudinal systolic function", "Diastolic dysfunction only", "Normal variant in young adults"], correctAnswer: 1, rationale: "Mitral annular s' velocity reflects longitudinal systolic function. Normal s' is >8 cm/s (septal) and >10 cm/s (lateral). Values <5 cm/s indicate severely impaired longitudinal systolic function, even if EF appears preserved. It is load-dependent and angle-dependent.", learningObjective: "Interpret mitral annular s' velocity", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal Ar-A duration difference for assessing LV filling pressures should be:", options: [">30 ms", "<30 ms (Ar duration should not exceed A duration by >30 ms)", "<0 ms always", ">100 ms"], correctAnswer: 1, rationale: "Ar-A duration: the difference between PV A reversal (Ar) duration and mitral A wave duration. Ar-A ≥30 ms suggests elevated LVEDP. This parameter is particularly useful in the 'indeterminate' E/e' range (8-14) for confirming elevated filling pressures.", learningObjective: "Interpret Ar-A duration for filling pressures", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 4, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An LVIDd of 62 mm in an adult male indicates:", options: ["Normal", "Mildly dilated LV", "Moderately dilated LV", "Severely dilated LV"], correctAnswer: 1, rationale: "Normal LVIDd for males: 42-58 mm. Mildly dilated: 59-63 mm, moderately dilated: 64-68 mm, severely dilated: ≥69 mm. An LVIDd of 62 mm falls in the mildly dilated range. LV dilation can be due to volume overload, DCM, or chronic valvular regurgitation.", learningObjective: "Classify LV size by LVIDd", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A pericardial effusion that causes hemodynamic compromise with only a small amount of rapidly accumulating fluid demonstrates that tamponade depends on:", options: ["Effusion size only", "The rate of fluid accumulation relative to pericardial compliance", "Only the type of fluid", "Only the patient's age"], correctAnswer: 1, rationale: "Tamponade physiology depends on: rate of accumulation (rapid accumulation overwhelms pericardial stretch), pericardial compliance, and intravascular volume. A small, rapidly accumulating effusion (e.g., post-procedural hemopericardium) can cause tamponade, while a large, slowly developing effusion may be well tolerated.", learningObjective: "Explain rate-dependent tamponade physiology", blueprintCategory: "Pathology Recognition", subtopic: "Pericardial Disease", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In Canadian echo labs, the preferred approach to quantifying valve regurgitation is:", options: ["Only qualitative assessment", "An integrative approach using multiple qualitative, semi-quantitative, and quantitative parameters to grade severity", "Only PISA method", "Only vena contracta"], correctAnswer: 1, rationale: "Canadian and international guidelines recommend an integrative approach: combining qualitative (jet character), semi-quantitative (vena contracta, jet area), and quantitative (EROA, RVol by PISA or volumetric method) parameters. No single parameter should be used in isolation for grading.", learningObjective: "Describe the integrative approach to valve regurgitation", blueprintCategory: "Hemodynamic Measurements", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "In a patient with a left ventricular assist device (LVAD), echo assessment should evaluate:", options: ["Only LV size", "Inflow and outflow cannula positions, aortic valve opening, RV function, interventricular septal position, and device-related complications", "Only EF", "Only mitral valve"], correctAnswer: 1, rationale: "LVAD echo assessment: inflow cannula position in the LV (avoid septal impingement), outflow graft patency, frequency of AV opening (intermittent opening prevents commissural fusion), RV function (critical for LVAD success), septal position (leftward shift = RV failure), TR, and pump parameters.", learningObjective: "Describe echo assessment of LVAD patients", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
  ];
}

export function getBatch24(): EQ[] {
  return [
    { stem: "An echo shows a large pericardial effusion with fibrinous strands. This is most consistent with:", options: ["Simple transudative effusion", "Exudative effusion (e.g., infectious, malignant, or post-surgical)", "Normal finding", "Cardiac tamponade always"], correctAnswer: 1, rationale: "Fibrinous strands within a pericardial effusion suggest an exudative process: infection (bacterial, TB), malignancy, post-surgical, or autoimmune pericarditis. Simple transudative effusions (CHF, hypothyroidism) are typically echo-free. Fibrinous adhesions may complicate drainage.", learningObjective: "Differentiate exudative from transudative pericardial effusion", blueprintCategory: "Pathology Recognition", subtopic: "Pericardial Disease", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal LV end-diastolic volume index (LVEDVI) for males is:", options: ["<30 mL/m²", "35-75 mL/m²", "80-100 mL/m²", ">120 mL/m²"], correctAnswer: 1, rationale: "Normal LVEDVI: 35-75 mL/m² for males, 35-68 mL/m² for females (ASE guidelines). LVEDVI >75 mL/m² indicates LV dilation. LVEDVI is more accurate than linear dimensions for assessing LV size, especially with regional remodeling.", learningObjective: "State normal LVEDVI", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In assessing LV diastolic function, the four recommended parameters are:", options: ["EF, FS, mass, and volume", "E/A ratio, average E/e', TR velocity, and LAVI", "LVOT VTI, AV VTI, DVI, and AVA", "TAPSE, FAC, s', and Tei index"], correctAnswer: 1, rationale: "The four key parameters for diastolic function assessment (ASE/EACVI 2016): (1) mitral annular e' velocity, (2) average E/e' ratio, (3) TR peak velocity, (4) LA volume index. If >50% are abnormal, diastolic dysfunction is present. The E/A ratio determines the grade.", learningObjective: "List the four recommended diastolic function parameters", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An ascending aorta diameter of 5.5 cm in a patient without known connective tissue disease warrants:", options: ["Routine follow-up in 5 years", "Consideration for prophylactic surgical repair", "No intervention needed", "Only medical therapy"], correctAnswer: 1, rationale: "In patients without Marfan or bicuspid valve, prophylactic ascending aortic repair is generally recommended at ≥5.5 cm. For BAV, the threshold is ≥5.0-5.5 cm depending on risk factors. For Marfan, ≥5.0 cm (or ≥4.5 cm with risk factors).", learningObjective: "State surgical threshold for ascending aortic dilation", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The apical variant of HCM shows hypertrophy predominantly in the:", options: ["Basal septum", "LV apex with 'ace of spades' configuration on diastolic A4C view", "RV free wall", "Lateral wall only"], correctAnswer: 1, rationale: "Apical HCM: disproportionate hypertrophy of the LV apex creating the classic 'ace of spades' (or 'spade-shaped') LV cavity in diastole on the A4C view. It is more common in Japanese populations. It may be missed if the apex is foreshortened on echo. Associated with giant negative T-waves on ECG.", learningObjective: "Describe apical HCM echo findings", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient presents with syncope and echo shows severe AS. The appropriate next step is:", options: ["Repeat echo in 6 months", "Urgent referral for aortic valve replacement (surgical or TAVR)", "Exercise stress test", "Medical therapy only"], correctAnswer: 1, rationale: "Symptomatic severe AS (syncope, angina, or heart failure) has a very poor prognosis with medical therapy alone (50% mortality at 2 years). Urgent referral for aortic valve replacement (surgical AVR or TAVR depending on surgical risk) is indicated. Exercise testing is contraindicated in symptomatic severe AS.", learningObjective: "Manage symptomatic severe AS", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "application", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In a patient with atrial fibrillation, the mitral A wave is:", options: ["Increased", "Absent (no organized atrial contraction)", "Unchanged", "Reversed"], correctAnswer: 1, rationale: "In AF, the loss of organized atrial contraction eliminates the mitral A wave on Doppler. The E/A ratio cannot be calculated, and diastolic function assessment requires alternative parameters (E/e', LAVI, TR velocity). LAA velocities <20 cm/s in AF indicate high thromboembolic risk.", learningObjective: "Describe effect of AF on mitral inflow Doppler", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient with severe AS and low EF (30%) has a mean gradient of only 25 mmHg. Low-dose dobutamine stress echo is performed to determine:", options: ["Exercise capacity", "Whether the AS is truly severe (true severe) or pseudo-severe (mild-moderate AS with low flow)", "The degree of coronary artery disease", "Diastolic function grade"], correctAnswer: 1, rationale: "Low-dose dobutamine (5-20 mcg/kg/min) increases flow through the aortic valve. In true severe AS, AVA remains <1.0 cm² and gradient increases. In pseudo-severe AS, AVA increases to >1.0 cm² as the valve opens more with increased flow. Contractile reserve (SV increase ≥20%) also predicts surgical outcome.", learningObjective: "Explain the purpose of dobutamine stress in low-flow AS", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 4, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal tricuspid annular s' velocity by TDI is:", options: ["<5 cm/s", "<9.5 cm/s", "≥9.5 cm/s", ">20 cm/s"], correctAnswer: 2, rationale: "Normal tricuspid annular s' ≥9.5 cm/s. Values <9.5 cm/s indicate RV systolic dysfunction. s' is measured by PW TDI at the lateral tricuspid annulus in the A4C view. It complements TAPSE and FAC for RV function assessment.", learningObjective: "State normal tricuspid annular s' velocity", blueprintCategory: "Hemodynamic Measurements", subtopic: "RV Function Assessment", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "RV global longitudinal strain (RV GLS) normal value is approximately:", options: ["-10%", "-15%", "-20 to -25%", "-30 to -35%"], correctAnswer: 2, rationale: "Normal RV free wall longitudinal strain is approximately -25 ± 5% (vendor-dependent). Values less negative than -20% suggest RV dysfunction. RV GLS provides incremental value over TAPSE, FAC, and s' for detecting subclinical RV dysfunction.", learningObjective: "State normal RV GLS", blueprintCategory: "Hemodynamic Measurements", subtopic: "RV Function Assessment", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The '60-60 sign' in acute pulmonary embolism refers to:", options: ["RVSP = 60 mmHg and heart rate = 60", "RVSP <60 mmHg combined with RVOT acceleration time <60 ms", "RV diameter = 60 mm", "PA diameter = 60 mm"], correctAnswer: 1, rationale: "The 60-60 sign: RVSP <60 mmHg (because the acutely dilated, non-hypertrophied RV cannot generate higher pressures) AND RVOT acceleration time <60 ms (reflecting increased pulmonary vascular impedance). This combination helps differentiate acute PE from chronic pulmonary hypertension.", learningObjective: "Describe the 60-60 sign in acute PE", blueprintCategory: "Pathology Recognition", subtopic: "Hemodynamics", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a large, immobile, layered thrombus in the LV apex with a thin mobile component. The management risk is:", options: ["No risk", "High risk for systemic embolization from the mobile component", "Only cosmetic concern", "Spontaneous resolution expected"], correctAnswer: 1, rationale: "Mobile thrombus components and protruding thrombus have higher embolic risk than flat, laminated (organized) thrombus. Even with anticoagulation, mobile thrombi carry significant embolic risk. Serial echo monitoring to assess for resolution or mobilization is important.", learningObjective: "Assess embolic risk of LV thrombus morphology", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 3, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Contrast echocardiography for LV opacification uses a low mechanical index (MI) because:", options: ["Higher MI improves contrast", "Low MI (<0.2-0.3) preserves microbubble integrity, preventing premature destruction", "MI has no effect on contrast agents", "Low MI improves frame rate"], correctAnswer: 1, rationale: "Microbubble contrast agents are destroyed by high acoustic pressures. Low MI (<0.2-0.3) preserves bubble integrity for continuous real-time imaging. High MI (flash/burst mode) is used for replenishment kinetics in myocardial perfusion imaging.", learningObjective: "Explain low MI imaging for contrast echo", blueprintCategory: "Ultrasound Physics", subtopic: "Advanced Echo Techniques", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo in a patient with hypereosinophilic syndrome shows biventricular apical thrombus. The diagnosis is:", options: ["Isolated LV thrombus", "Löffler endocarditis with characteristic biventricular apical involvement", "Myxoma", "Normal variant"], correctAnswer: 1, rationale: "Löffler endocarditis (hypereosinophilic endocarditis) characteristically involves both ventricular apices with thrombus overlying thickened, fibrotic endocardium. Biventricular apical thrombus in the setting of eosinophilia is virtually diagnostic.", learningObjective: "Diagnose Löffler endocarditis from echo pattern", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 5, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A CSCT candidate should understand that the most important safety consideration in TEE is:", options: ["Image quality", "Patient airway management and esophageal injury prevention, including proper sedation, probe inspection, and monitoring", "Achieving all 28 views", "Cost efficiency"], correctAnswer: 1, rationale: "TEE safety priorities: patient airway management (proper sedation with monitoring), esophageal injury prevention (probe inspection before use, contraindication screening for esophageal disease), aspiration prevention (NPO status), and continuous hemodynamic monitoring throughout the procedure.", learningObjective: "Identify the primary safety consideration in TEE", blueprintCategory: "Ultrasound Physics", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "Contraindications to TEE include:", options: ["Mild dental disease", "Esophageal stricture, recent esophageal surgery, active upper GI bleeding, esophageal varices, and cervical spine instability", "Minor sore throat", "Mild anxiety"], correctAnswer: 1, rationale: "Absolute TEE contraindications: esophageal stricture/obstruction, esophageal perforation/laceration, recent esophageal or gastric surgery, active upper GI bleeding. Relative: esophageal varices, Barrett's esophagus, cervical spine instability, severe coagulopathy, radiation to chest/mediastinum.", learningObjective: "List TEE contraindications", blueprintCategory: "Ultrasound Physics", subtopic: "TEE Imaging", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In echo, the term 'preload' refers to:", options: ["Blood pressure", "The volume of blood in the ventricle at end-diastole (end-diastolic volume)", "Heart rate", "Valve function"], correctAnswer: 1, rationale: "Preload is the ventricular volume (or pressure) at end-diastole, reflecting the degree of myocardial fiber stretch before contraction. On echo, preload is assessed by LV dimensions, volumes, IVC size/collapsibility, and E wave velocity. It is a key determinant of stroke volume via Frank-Starling.", learningObjective: "Define preload in echo context", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Physiology", difficulty: 1, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Afterload in echocardiography is best reflected by:", options: ["Heart rate", "Wall stress during systole (related to systolic blood pressure, LV cavity size, and wall thickness)", "E wave velocity", "TAPSE"], correctAnswer: 1, rationale: "Afterload: the resistance against which the ventricle must eject. It is reflected by wall stress = (P × r) / (2h) per LaPlace. Clinically, it is approximated by systolic blood pressure and SVR. Increased afterload decreases stroke volume and EF. Decreased afterload (vasodilators) improves EF.", learningObjective: "Define afterload in echo context", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Physiology", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The compliance of the left ventricle determines:", options: ["Systolic function only", "The relationship between LV volume change and pressure change during diastolic filling (dV/dP)", "Heart rate", "Valve area"], correctAnswer: 1, rationale: "LV compliance (dV/dP): the change in volume per change in pressure during filling. Decreased compliance (stiff ventricle) causes filling pressures to rise for any given volume. This is the fundamental abnormality in diastolic heart failure (HFpEF) and is reflected by elevated E/e' ratio.", learningObjective: "Define LV compliance", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Physiology", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient with hypertrophic cardiomyopathy has an LVOT gradient of 25 mmHg at rest. After Valsalva, the gradient increases to 80 mmHg. This confirms:", options: ["Fixed obstruction", "Labile (latent) obstructive HCM with provocable LVOT obstruction", "Normal response", "Aortic stenosis"], correctAnswer: 1, rationale: "A resting LVOT gradient <30 mmHg that increases to ≥30 mmHg with provocation (Valsalva, standing, exercise) defines labile (latent) obstructive HCM. Valsalva decreases preload, making the LVOT narrower and increasing SAM. This is clinically significant and may respond to medical or interventional therapy.", learningObjective: "Diagnose labile obstructive HCM", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
  ];
}

export function getBatch25(): EQ[] {
  return [
    { stem: "The normal septal e' velocity decreases with age. In a 60-year-old, a septal e' of:", options: ["5 cm/s is normal", "8 cm/s is likely normal for age", "15 cm/s is expected", "20 cm/s is normal"], correctAnswer: 1, rationale: "e' velocity decreases with age: ~15 cm/s at age 20, ~10 cm/s at age 50, ~8 cm/s at age 60, ~5-7 cm/s at age 80. A septal e' of 8 cm/s in a 60-year-old is at the lower range of normal for age but still within expected values. Age-specific cutoffs should be considered.", learningObjective: "Interpret age-related changes in e' velocity", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Tricuspid valve annuloplasty ring assessment on echo requires evaluation of:", options: ["Only gradient", "Annuloplasty ring size, residual TR, transprosthetic gradient, and ring dehiscence", "Only visual inspection", "Only EF"], correctAnswer: 1, rationale: "After tricuspid annuloplasty, echo should assess: ring integrity and position, residual TR severity, transprosthetic gradient (significant stenosis >5 mmHg mean), and ring dehiscence (rocking motion, paravalvular leak). Tricuspid stenosis from an undersized ring can occur.", learningObjective: "Describe post-annuloplasty echo assessment", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo measurement of PISA radius of 10 mm with aliasing velocity of 40 cm/s and peak MR velocity of 5 m/s gives an EROA of:", options: ["0.20 cm²", "0.25 cm²", "0.50 cm²", "0.75 cm²"], correctAnswer: 2, rationale: "EROA = 2π × r² × Va / Vmax = 2π × (1.0)² × 40 / 500 = 2 × 3.14 × 1.0 × 40 / 500 = 251.2 / 500 = 0.50 cm². This exceeds the severe MR threshold for primary MR (EROA ≥0.40 cm²), confirming severe MR.", learningObjective: "Calculate EROA from PISA measurements", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 4, cognitiveLevel: "application", questionType: "calculation", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Gorlin formula for valve area uses:", options: ["Only Doppler data", "Cardiac output, heart rate, systolic/diastolic filling period, and mean gradient (typically from catheterization data)", "Only echo measurements", "Only angiographic data"], correctAnswer: 1, rationale: "Gorlin formula: valve area = cardiac output / (heart rate × filling period × C × √mean gradient). It is primarily used with catheterization data but illustrates the relationship between flow, gradient, and valve area. Echo methods (continuity, PHT, planimetry) have largely replaced it clinically.", learningObjective: "Describe the Gorlin formula", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In echo assessment of prosthetic valve function, an elevated gradient compared to the baseline postoperative study suggests:", options: ["Normal aging of the valve", "Possible prosthetic valve obstruction (thrombus, pannus) or patient-prosthesis mismatch, requiring further investigation", "Improved valve function", "Technical error only"], correctAnswer: 1, rationale: "Comparison with baseline postoperative values is essential for prosthetic valve assessment. An increase in gradient >50% from baseline or above the expected range for valve type/size suggests obstruction (thrombus, pannus, valve degeneration) and warrants further investigation (TEE, fluoroscopy, CT).", learningObjective: "Interpret elevated prosthetic valve gradients", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A Ross procedure involves:", options: ["Mechanical valve replacement", "Replacing the aortic valve with the patient's own pulmonary valve (pulmonary autograft) and placing a homograft in the pulmonary position", "Mitral valve repair only", "TAVR"], correctAnswer: 1, rationale: "Ross procedure: the diseased aortic valve is replaced with the patient's native pulmonary valve (autograft), and a pulmonary homograft is placed in the pulmonary position. Echo follow-up monitors both the neo-aortic root (dilation risk) and the pulmonary homograft (stenosis/regurgitation).", learningObjective: "Describe the Ross procedure", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A Bentall procedure for aortic root replacement includes:", options: ["Only valve replacement", "Composite replacement of the aortic valve, aortic root, and ascending aorta with reimplantation of the coronary arteries", "Only ascending aortic repair", "Descending aortic repair"], correctAnswer: 1, rationale: "Bentall procedure: composite graft replacement of the aortic valve + aortic root + ascending aorta (mechanical or bioprosthetic valve-conduit) with coronary artery reimplantation (button technique). Echo follow-up monitors prosthetic valve function, graft integrity, and coronary button sites.", learningObjective: "Describe the Bentall procedure", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "David procedure (valve-sparing aortic root replacement) preserves the native:", options: ["Mechanical valve", "Aortic valve leaflets while replacing the aortic root and ascending aorta", "Mitral valve", "Pulmonic valve"], correctAnswer: 1, rationale: "David procedure: the native aortic valve leaflets are preserved and reimplanted within a synthetic graft (reimplantation technique). This avoids the need for anticoagulation or risk of bioprosthetic degeneration. Echo follow-up monitors for AR development and graft dimensions.", learningObjective: "Describe the David procedure", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the CSCT exam, understanding of appropriate use criteria (AUC) for echocardiography is tested because:", options: ["AUC are irrelevant", "Sonographers should understand when echo is appropriate, inappropriate, or may be appropriate, to support clinical decision-making and avoid unnecessary studies", "Only physicians need this knowledge", "AUC only apply in the US"], correctAnswer: 1, rationale: "Canadian echo labs are expected to follow appropriate use criteria to ensure echo is performed when it will provide meaningful clinical information. CSCT candidates should understand AUC categories: appropriate (clearly beneficial), may be appropriate (uncertain benefit), and rarely appropriate (unlikely to improve outcomes).", learningObjective: "Explain the role of AUC in echo practice", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "In CSCT practice, echo findings should always be correlated with:", options: ["Only previous echo reports", "Clinical history, symptoms, physical examination findings, ECG, and other imaging results for comprehensive patient assessment", "Only laboratory values", "Nothing additional"], correctAnswer: 1, rationale: "Echo findings must be interpreted in clinical context. Canadian standards emphasize correlation with symptoms, physical exam, ECG, laboratory data, and other imaging. Isolated echo findings without clinical correlation can lead to misinterpretation and inappropriate management.", learningObjective: "Describe the importance of clinical correlation in echo", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "An RWT of 0.50 with a normal LV mass index indicates:", options: ["Normal geometry", "Concentric remodeling (increased wall-to-cavity ratio without increased mass)", "Eccentric hypertrophy", "Concentric hypertrophy"], correctAnswer: 1, rationale: "LV geometry classification: Normal (RWT ≤0.42, normal mass index), Concentric remodeling (RWT >0.42, normal mass index), Eccentric hypertrophy (RWT ≤0.42, increased mass index), Concentric hypertrophy (RWT >0.42, increased mass index). Concentric remodeling is seen in early hypertension.", learningObjective: "Classify LV geometry from RWT and mass", blueprintCategory: "Hemodynamic Measurements", subtopic: "Chamber Quantification", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows an aneurysm of the membranous ventricular septum. This is:", options: ["Always pathologic", "A common finding associated with spontaneous closure or partial closure of a perimembranous VSD", "A surgical emergency", "Only seen in infants"], correctAnswer: 1, rationale: "Membranous septal aneurysm: a pouch-like outpouching of the membranous septum into the RV, often representing partial or complete spontaneous closure of a perimembranous VSD by tricuspid valve tissue. It may have a small residual VSD. It is generally benign but can rarely obstruct the RVOT.", learningObjective: "Describe membranous septal aneurysm", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a dilated RA and RV with severe TR and a pacemaker lead crossing the tricuspid valve. The most likely cause of TR is:", options: ["Primary leaflet disease", "Pacemaker lead-induced tricuspid regurgitation from leaflet impingement or adherence", "Carcinoid disease", "Ebstein anomaly"], correctAnswer: 1, rationale: "Pacemaker/ICD leads crossing the tricuspid valve can cause TR by: direct leaflet impingement, adhesion/fibrosis to leaflets, restricted closure, or perforation. The incidence of clinically significant TR after lead placement is substantial and may worsen over time.", learningObjective: "Identify pacemaker lead as a cause of TR", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 2, cognitiveLevel: "application", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In a patient with severe MR, an LV with ESD >40 mm (or ESVI >30 mL/m²) or EF ≤60% suggests:", options: ["Normal compensated state", "LV systolic dysfunction from chronic MR volume overload, indicating need for surgical intervention even if asymptomatic", "Irreversible damage not amenable to surgery", "Only medical therapy needed"], correctAnswer: 1, rationale: "In chronic severe MR, ESD >40 mm or EF ≤60% indicates early LV systolic dysfunction from volume overload (these thresholds are lower than normal because the favorable loading conditions of MR normally augment EF). These are triggers for surgical intervention even in asymptomatic patients.", learningObjective: "Identify surgical triggers in chronic severe MR", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 4, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The PISA method assumes the proximal isovelocity surface is:", options: ["Flat", "Hemispheric (half-sphere) in shape", "Cylindrical", "Cubic"], correctAnswer: 1, rationale: "PISA assumes a hemispheric flow convergence zone. The hemispheric surface area = 2πr². Deviations from this assumption (e.g., due to constraining surfaces, non-circular orifice) can introduce errors. The PISA method works best with central regurgitant jets.", learningObjective: "Describe the geometric assumption of PISA", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "During an echo-guided pericardiocentesis, agitated saline can be injected through the needle to:", options: ["Assess for PFO", "Confirm the needle tip is in the pericardial space (bubbles appear in the pericardial effusion, not in a cardiac chamber)", "Measure cardiac output", "Assess diastolic function"], correctAnswer: 1, rationale: "Agitated saline injected through the pericardiocentesis needle creates echogenic bubbles. If the needle is correctly positioned in the pericardial space, bubbles appear in the effusion. If bubbles appear in a cardiac chamber, the needle has entered the heart (requires repositioning).", learningObjective: "Describe saline confirmation during pericardiocentesis", blueprintCategory: "Pathology Recognition", subtopic: "Pericardial Disease", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A strain bull's-eye plot showing uniform red coloring (positive or near-zero strain) in the basal segments with relatively preserved apical strain (normal negative blue) is the classic pattern for:", options: ["Normal heart", "Cardiac amyloidosis (apical sparing pattern)", "Takotsubo", "HCM"], correctAnswer: 1, rationale: "The apical sparing pattern on GLS bull's-eye plot: reduced (less negative/positive) strain at the base and mid-ventricular segments with relatively preserved (more negative) apical strain. This pattern is highly specific for cardiac amyloidosis (cherry on top pattern).", learningObjective: "Identify the amyloid GLS pattern on bull's-eye plot", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 4, cognitiveLevel: "analysis", questionType: "image-interpretation", exam: "RDCS-AE", regionScope: "BOTH", exhibitData: { description: "GLS bull's-eye plot showing red/orange (reduced strain) at base and mid-segments with blue (preserved strain) at apex", findings: ["Apical sparing pattern", "Basal strain reduction", "Characteristic amyloid pattern"] } },
    { stem: "An echo in a patient with chronic severe AR shows LV dilation (LVEDVI 150 mL/m²), EF 55%, and LVESD 48 mm. The patient is asymptomatic. Surgery should be:", options: ["Deferred until symptoms develop", "Recommended based on LV dilation and LVESD approaching surgical threshold (≥50 mm or LVEDVI ≥250 mL)", "Performed immediately", "Never considered in asymptomatic patients"], correctAnswer: 1, rationale: "Chronic severe AR surgical triggers in asymptomatic patients: EF ≤55%, LVESD ≥50 mm (or ≥25 mm/m²), or progressive LV dilation. With LVESD 48 mm and LVEDVI 150 mL/m², this patient is approaching but has not met absolute surgical criteria. Close follow-up (every 3-6 months) is warranted.", learningObjective: "Apply surgical timing criteria in chronic severe AR", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 4, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the CSCT exam, understanding of echo in the emergency department includes:", options: ["Echo is not used in emergencies", "Focused echo protocols (FATE, RUSH) for rapid assessment of cardiac tamponade, RV dilation, LV function, and volume status in acute presentations", "Only comprehensive studies", "Only by cardiologists"], correctAnswer: 1, rationale: "CSCT candidates must understand focused echo in emergencies: FATE (Focus Assessed Transthoracic Echo) and RUSH (Rapid Ultrasound in Shock and Hypotension) protocols provide rapid bedside assessment of cardiac structure and function to guide emergent management.", learningObjective: "Describe emergency echo protocols", blueprintCategory: "Ultrasound Physics", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
  ];
}
